// const: nilai tidak bisa diubah — gunakan sebagai default
const namaSitus = 'Web Belajar Informatika';
const tahunBerdiri = 2024;
// namaSitus = 'Ganti'; // ERROR! const tidak bisa di-reassign

// let: nilai bisa diubah
let nilaiMahasiswa = 75;
nilaiMahasiswa = 80;  // OK!
nilaiMahasiswa += 5;  // Sekarang jadi 85

// var — hindari di kode modern
var statusLama = 'aktif';  // Jangan dipakai

// Deklarasi banyak variabel sekaligus
let nama = 'Budi', umur = 20, kota = 'Jakarta';

// Variabel tanpa nilai = undefined
let belumDiisi;
console.log(belumDiisi);  // undefined

// String
const nama = 'Budi Santoso';
const kota = "Yogyakarta";
const pesan = `Halo, nama saya ${nama}`;  // template literal

// Number
const umur = 21;
const ipk = 3.75;
const suhu = -5;
console.log(10 / 0);   // Infinity
console.log('abc' * 2); // NaN (Not a Number)

// Boolean
const sudahLogin = true;
const isPremium = false;

// Null vs Undefined
let fotoProfil = null;    // sengaja dikosongkan
let alamat;               // belum diisi = undefined

// Mengecek tipe data dengan typeof
console.log(typeof nama);        // 'string'
console.log(typeof umur);        // 'number'
console.log(typeof sudahLogin);  // 'boolean'
console.log(typeof alamat);      // 'undefined'
console.log(typeof null);        // 'object' ← bug historis JS!
console.log(typeof [1,2,3]);     // 'object'
console.log(typeof function(){}); // 'function'

// Aritmatika
console.log(10 + 3);   // 13
console.log(10 % 3);   // 1 (sisa bagi)
console.log(2 ** 8);   // 256 (2 pangkat 8)
console.log('Halo' + ' ' + 'Dunia'); // 'Halo Dunia' (string concatenation)

// Jebakan operator +
console.log('5' + 3);  // '53' (string!), bukan 8!
console.log('5' - 3);  // 2 (number) — minus tidak bisa concat

// Perbandingan: == vs ===
console.log(5 == '5');  // true  — BERBAHAYA, hindari!
console.log(5 === '5'); // false — aman, cek tipe juga
console.log(null == undefined);  // true
console.log(null === undefined); // false

// Logika
const umur = 20;
const punyaKTP = true;
console.log(umur >= 17 && punyaKTP); // true (AND)
console.log(umur < 17 || punyaKTP);  // true (OR)
console.log(!punyaKTP);              // false (NOT)

// Ternary operator: kondisi ? nilaiJikaTrue : nilaiJikaFalse
const status = umur >= 17 ? 'Dewasa' : 'Anak-anak';
console.log(status); // 'Dewasa'

// Nullish coalescing: ?? — gunakan nilai default jika null/undefined
const namaUser = null;
console.log(namaUser ?? 'Tamu'); // 'Tamu'

// if / else if / else
const nilai = 78;

if (nilai >= 90) {
  console.log('Grade A — Sangat Baik');
} else if (nilai >= 80) {
  console.log('Grade B — Baik');
} else if (nilai >= 70) {
  console.log('Grade C — Cukup');  // ← ini yang dijalankan
} else if (nilai >= 60) {
  console.log('Grade D — Kurang');
} else {
  console.log('Grade E — Tidak Lulus');
}

// switch — lebih rapi untuk banyak kemungkinan nilai yang pasti
const hari = 'Senin';

switch (hari) {
  case 'Senin':
  case 'Selasa':
  case 'Rabu':
  case 'Kamis':
  case 'Jumat':
    console.log('Hari kerja');
    break;  // WAJIB! tanpa break, eksekusi lanjut ke case berikutnya
  case 'Sabtu':
  case 'Minggu':
    console.log('Akhir pekan!');
    break;
  default:
    console.log('Hari tidak dikenal');
}

// Truthy & Falsy dalam kondisi
const username = '';  // string kosong = falsy
if (username) {
  console.log(`Halo, ${username}!`);
} else {
  console.log('Silakan login terlebih dahulu');
}

// Optional chaining: akses property yang mungkin null/undefined
const user = null;
console.log(user?.nama ?? 'Nama tidak tersedia');

// for loop: paling umum
for (let i = 1; i <= 5; i++) {
  console.log(`Iterasi ke-${i}`);
}
// Output: Iterasi ke-1, ke-2, ke-3, ke-4, ke-5

// Contoh nyata: hitung total belanja
const harga = [15000, 25000, 8000, 42000];
let total = 0;
for (let i = 0; i < harga.length; i++) {
  total += harga[i];
}
console.log(`Total: Rp${total}`); // Total: Rp90000

// for...of: lebih bersih untuk iterasi array
const buah = ['Mangga', 'Apel', 'Pisang', 'Jeruk'];
for (const item of buah) {
  console.log(`🍎 ${item}`);
}

// while loop: jalankan selama kondisi true
let stok = 5;
while (stok > 0) {
  console.log(`Stok tersisa: ${stok}`);
  stok--;
}

// break: hentikan loop lebih awal
for (let i = 0; i < 10; i++) {
  if (i === 5) break;  // berhenti di i=5
  console.log(i);      // hanya tampil 0,1,2,3,4
}

// continue: lewati iterasi tertentu
for (let i = 1; i <= 10; i++) {
  if (i % 2 === 0) continue;  // lewati angka genap
  console.log(i);  // hanya angka ganjil: 1,3,5,7,9
}

// for...in: iterasi property object
const mahasiswa = { nama: 'Budi', nim: '2021001', ipk: 3.75 };
for (const key in mahasiswa) {
  console.log(`${key}: ${mahasiswa[key]}`);
}

// 1. Function Declaration — bisa dipanggil sebelum didefinisikan (hoisting)
function hitungLuas(panjang, lebar) {
  const luas = panjang * lebar;
  return luas;  // kembalikan nilai ke pemanggil
}
console.log(hitungLuas(5, 3)); // 15

// 2. Function Expression — disimpan ke variabel, tidak di-hoist
const hitungKeliling = function(panjang, lebar) {
  return 2 * (panjang + lebar);
};
console.log(hitungKeliling(5, 3)); // 16

// 3. Arrow Function — sintaks ringkas, diperkenalkan ES6
const kuadrat = (n) => n * n;         // satu expression, no return needed
const kali = (a, b) => a * b;
const sapa = nama => `Halo, ${nama}!`; // satu parameter, no parentheses

console.log(kuadrat(7));   // 49
console.log(sapa('Budi')); // 'Halo, Budi!'

// Default parameter: nilai default jika argumen tidak dikirim
function buat_sambutan(nama = 'Tamu', gelar = 'Sdr.') {
  return `Selamat datang, ${gelar} ${nama}!`;
}
console.log(buat_sambutan());           // 'Selamat datang, Sdr. Tamu!'
console.log(buat_sambutan('Budi', 'Dr.')); // 'Selamat datang, Dr. Budi!'

// Rest parameter: terima jumlah argumen tidak terbatas
function jumlahkan(...angka) {
  return angka.reduce((total, n) => total + n, 0);
}
console.log(jumlahkan(1, 2, 3, 4, 5)); // 15

// Membuat array
const nilai = [75, 82, 90, 68, 95, 71];
const buah = ['Mangga', 'Apel', 'Pisang'];

// Mengakses elemen (zero-indexed)
console.log(nilai[0]);  // 75 (pertama)
console.log(nilai[nilai.length - 1]); // 71 (terakhir)

// Menambah & menghapus
buah.push('Jeruk');        // ['Mangga', 'Apel', 'Pisang', 'Jeruk']
buah.pop();                // hapus 'Jeruk'
buah.unshift('Semangka');  // tambah di awal

// map: transformasi setiap elemen → array baru
const nilaiPlusBonus = nilai.map(n => n + 5);
console.log(nilaiPlusBonus); // [80, 87, 95, 73, 100, 76]

// filter: saring elemen yang memenuhi kondisi
const lulusUjian = nilai.filter(n => n >= 75);
console.log(lulusUjian); // [75, 82, 90, 95]

// find: cari elemen pertama yang memenuhi kondisi
const nilaiPertamaDiAtas90 = nilai.find(n => n > 90);
console.log(nilaiPertamaDiAtas90); // 95

// reduce: akumulasi → satu nilai
const totalNilai = nilai.reduce((akum, n) => akum + n, 0);
const rataRata = totalNilai / nilai.length;
console.log(`Rata-rata: ${rataRata}`); // Rata-rata: 80.17

// includes & indexOf
console.log(buah.includes('Apel')); // true
console.log(buah.indexOf('Apel')); // 1

// Spread operator: salin atau gabung array
const nilaiTambahan = [88, 77];
const semuaNilai = [...nilai, ...nilaiTambahan];
console.log(semuaNilai); // [75, 82, 90, 68, 95, 71, 88, 77]

// Destructuring array
const [pertama, kedua, ...sisanya] = nilai;
console.log(pertama); // 75
console.log(kedua);   // 82
console.log(sisanya); // [90, 68, 95, 71]

// Membuat object
const mahasiswa = {
  nama: 'Siti Rahayu',
  nim: '2021002',
  jurusan: 'Teknik Informatika',
  ipk: 3.85,
  hobi: ['Coding', 'Membaca', 'Hiking'],
  alamat: {
    kota: 'Bandung',
    provinsi: 'Jawa Barat'
  },
  // Method: fungsi sebagai property
