// Mengakses property
console.log(mahasiswa.nama);           // 'Siti Rahayu'
console.log(mahasiswa['ipk']);          // 3.85
console.log(mahasiswa.alamat.kota);    // 'Bandung'
console.log(mahasiswa.hobi[0]);        // 'Coding'
console.log(mahasiswa.perkenalan());   // 'Halo, saya Siti Rahayu...'

// Menambah & mengubah property
mahasiswa.email = 'siti@email.com';    // tambah property baru
mahasiswa.ipk = 3.90;                  // ubah nilai

// Menghapus property
delete mahasiswa.hobi;

// Destructuring object
const { nama, jurusan, ipk } = mahasiswa;
console.log(nama);    // 'Siti Rahayu'
console.log(jurusan); // 'Teknik Informatika'

// Destructuring dengan rename
const { nama: namaLengkap, ipk: nilaiIPK } = mahasiswa;
console.log(namaLengkap); // 'Siti Rahayu'

// Spread operator: salin object
const mahasiswaUpdate = { ...mahasiswa, ipk: 3.95, angkatan: 2021 };

// Object.keys, Object.values, Object.entries
console.log(Object.keys(mahasiswa));    // ['nama', 'nim', 'jurusan', ...]
console.log(Object.values(mahasiswa));  // ['Siti Rahayu', '2021002', ...]
