// Shorthand property
const kota = 'Jakarta';
const umur = 22;
const profil = { kota, umur }; // sama dengan { kota: kota, umur: umur }
console.log(profil); // { kota: 'Jakarta', umur: 22 }

const judul = '  Belajar JavaScript Bersama  ';

// Membersihkan & mengubah case
console.log(judul.trim());         // 'Belajar JavaScript Bersama'
console.log(judul.trim().toUpperCase()); // 'BELAJAR JAVASCRIPT BERSAMA'
console.log(judul.trim().toLowerCase()); // 'belajar javascript bersama'

// Mencari
const email = 'budi@example.com';
console.log(email.includes('@'));          // true
console.log(email.startsWith('budi'));     // true
console.log(email.endsWith('.com'));       // true
