// Memecah string
const csv = 'Budi,Siti,Ahmad,Dewi';
const namaMahasiswa = csv.split(',');
console.log(namaMahasiswa); // ['Budi', 'Siti', 'Ahmad', 'Dewi']

// Menggabungkan array menjadi string
