// Template literal
const nama = 'Budi';
const ipk = 3.75;
console.log(`Mahasiswa ${nama} memiliki IPK ${ipk}`);
console.log(`${ipk >= 3.5 ? 'Cumlaude!' : 'Tetap semangat!'}`);

// Manipulasi Number
console.log(parseInt('42px'));     // 42 (ambil angka dari string)
console.log(parseFloat('3.14rem')); // 3.14
console.log(Number('100'));         // 100
console.log(Number('abc'));         // NaN

// Math object
console.log(Math.round(3.7));   // 4 (bulatkan)
console.log(Math.floor(3.9));   // 3 (bulatkan ke bawah)
console.log(Math.ceil(3.1));    // 4 (bulatkan ke atas)
console.log(Math.max(5, 2, 8, 1)); // 8
console.log(Math.min(5, 2, 8, 1)); // 1
console.log(Math.abs(-42));     // 42 (nilai absolut)
