console.log(Math.random());     // angka acak 0–1

// Random angka dalam range
const acak1sampai10 = Math.floor(Math.random() * 10) + 1;

// Format angka sebagai mata uang
const harga = 150000;
console.log(harga.toLocaleString('id-ID', {
  style: 'currency',
  currency: 'IDR'
})); // 'Rp150.000,00'

// try...catch dasar
try {
  const data = null;
  console.log(data.nama); // TypeError: Cannot read properties of null
} catch (error) {
  console.log('Terjadi error:', error.message);
  console.log('Tipe error:', error.name); // 'TypeError'
} finally {
  // Selalu dijalankan, baik error maupun tidak
  console.log('Blok finally selalu jalan');
}

// Melempar error custom dengan throw
function bagi(a, b) {
  if (b === 0) {
    throw new Error('Tidak bisa membagi dengan nol!');
  }
  return a / b;
}

try {
  console.log(bagi(10, 2));  // 5
  console.log(bagi(10, 0));  // melempar Error
} catch (err) {
  console.error('Error:', err.message);
}

// Error handling untuk fetch API (async)
async function ambilData(url) {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
    const data = await response.json();
    return data;
  } catch (err) {
    console.error('Gagal mengambil data:', err.message);
    return null;  // kembalikan null jika gagal
  }
}
